CODE_EXAMPLE:
// Before
int getPrice() {
  int basePrice = quantity * itemPrice;
  int seasonalDiscount = getSeason().getDiscount();
  return applyDiscount(basePrice, seasonalDiscount);
}

int applyDiscount(int basePrice, int discount) {
  return basePrice - discount;
}

// After
int getPrice() {
  int basePrice = quantity * itemPrice;
  return applyDiscount(basePrice);
}

int applyDiscount(int basePrice) {
  return basePrice - getSeason().getDiscount();
}

